"use client"

import { useState, useEffect } from "react"
import { useTheme } from "next-themes"
import { Button } from "@/components/ui/button"
import { ScrollArea } from "@/components/ui/scroll-area"
import { Card, CardHeader, CardTitle, CardDescription, CardFooter } from "@/components/ui/card"
import {
  Moon, Sun, ArrowUp, ArrowRight,
  Plus, Mic, Paperclip, Image as ImageIcon,
  Lightbulb, Telescope, MoreHorizontal, Folder, ChevronRight
} from "lucide-react"
import { useRouter } from "next/navigation"

// 模拟课程数据
const COURSE_LIST = [
  { id: 1, title: '西装领口高级工艺', desc: '掌握 2% 缩水率的核心换算，解决领口不服帖的工业级难题。', price: '¥299', tag: '高阶推荐' },
  { id: 2, title: '女装袖口收尖规程', desc: '从原型到成衣，15年打版实战经验总结。', price: '¥199', tag: '实战进阶' },
  { id: 3, title: '男裤立裆换算公式', desc: '告别死记硬背，一套公式吃透男裤立裆结构。', price: '¥99', tag: '基础必修' },
  { id: 4, title: '连袖结构与腋下折痕', desc: '处理连袖腋下堆量的独家几何切展方法。', price: '¥159', tag: '细节精讲' }
]

// 弹出菜单的子项组件
function MenuItem({ icon, label, hasArrow }: { icon: React.ReactNode, label: string, hasArrow?: boolean }) {
  return (
    <div className="flex items-center justify-between px-3 py-2.5 hover:bg-gray-200 dark:hover:bg-[#3a3a3a] cursor-pointer transition-colors mx-1 rounded-lg">
      <div className="flex items-center gap-3">
        <div className="text-gray-500 dark:text-zinc-400">{icon}</div>
        <span className="text-[15px] font-medium text-gray-800 dark:text-zinc-200">{label}</span>
      </div>
      {hasArrow && <ChevronRight size={16} className="text-gray-400 dark:text-zinc-500" />}
    </div>
  )
}

export default function Home() {
  const { setTheme, theme } = useTheme()
  const [mounted, setMounted] = useState(false)
  const [input, setInput] = useState("")
  const [messages, setMessages] = useState<{ role: string, content: string }[]>([])
  const [view, setView] = useState<'chat' | 'course'>('chat')

  // 控制 + 号弹出菜单的状态
  const [showPlusMenu, setShowPlusMenu] = useState(false)

  const router = useRouter()

  useEffect(() => {
    setMounted(true)

    // 点击页面其他区域时自动关闭弹出菜单
    const closeMenu = () => {
      if (showPlusMenu) setShowPlusMenu(false)
    }
    document.addEventListener('click', closeMenu)
    return () => document.removeEventListener('click', closeMenu)
  }, [showPlusMenu])

  const handleSend = () => {
    if (!input.trim()) return
    setMessages([...messages, { role: "user", content: input }])
    setInput("")
    setView('chat')
  }

  // 🎯 全新重构的输入框 (高仿 Gemini/Grok 语音输入栏风格)
  const ChatInput = (
    <div className="relative flex items-center bg-gray-100 dark:bg-[#282828] rounded-full pl-2 pr-2 py-1.5 w-full shadow-lg border border-transparent dark:border-zinc-700/50 transition-colors focus-within:border-gray-300 dark:focus-within:border-zinc-500">

      {/* 左侧加号与下拉菜单 */}
      <div className="relative">
        <button
          className="p-2.5 text-gray-500 dark:text-zinc-400 hover:text-gray-900 dark:hover:text-white transition-colors rounded-full hover:bg-gray-200 dark:hover:bg-zinc-700/50"
          onClick={(e) => {
            e.stopPropagation()
            setShowPlusMenu(!showPlusMenu)
          }}
        >
          <Plus size={22} className="stroke-[1.5]" />
        </button>

        {/* 弹出菜单 */}
        {showPlusMenu && (
          <div
            className="absolute bottom-[calc(100%+16px)] left-0 w-[240px] bg-white dark:bg-[#282828] border border-gray-200 dark:border-zinc-700/80 rounded-[1.25rem] py-2 shadow-2xl z-50"
            onClick={(e) => e.stopPropagation()}
          >
            <MenuItem icon={<Paperclip size={18} className="stroke-[1.5]" />} label="添加照片和文件" />
            <div className="h-[1px] bg-gray-200 dark:bg-zinc-700/50 my-1.5 mx-3" />
            <MenuItem icon={<ImageIcon size={18} className="stroke-[1.5]" />} label="创建图片" />
            <MenuItem icon={<Lightbulb size={18} className="stroke-[1.5]" />} label="思考一下" />
            <MenuItem icon={<Telescope size={18} className="stroke-[1.5]" />} label="深度研究" />
            <div className="h-[1px] bg-gray-200 dark:bg-zinc-700/50 my-1.5 mx-3" />
            <MenuItem icon={<MoreHorizontal size={18} className="stroke-[1.5]" />} label="更多" hasArrow />
            <div className="h-[1px] bg-gray-200 dark:bg-zinc-700/50 my-1.5 mx-3" />
            <MenuItem icon={<Folder size={18} className="stroke-[1.5]" />} label="项目" hasArrow />
          </div>
        )}
      </div>

      {/* 核心文本输入区 */}
      <input
        className="flex-1 bg-transparent border-none focus:outline-none text-gray-900 dark:text-white px-2 placeholder:text-gray-400 dark:placeholder:text-zinc-400 text-[15px]"
        placeholder="有问题，尽管问"
        value={input}
        onChange={(e) => setInput(e.target.value)}
        onKeyDown={(e) => e.key === 'Enter' && handleSend()}
      />

      {/* 右侧麦克风 */}
      <button className="p-2.5 text-gray-500 dark:text-zinc-400 hover:text-gray-900 dark:hover:text-white transition-colors rounded-full hover:bg-gray-200 dark:hover:bg-zinc-700/50 mr-1">
        <Mic size={20} className="stroke-[1.5]" />
      </button>

      {/* 最右侧白色实心按钮 (自定义音频波形或发送箭头) */}
      <button
        className="h-[38px] w-[38px] min-w-[38px] bg-black dark:bg-white rounded-full flex items-center justify-center transition-all duration-300 hover:scale-105 shadow-sm shrink-0"
        onClick={handleSend}
      >
        {input.trim() ? (
          <ArrowUp size={20} className="text-white dark:text-black stroke-[2.5]" />
        ) : (
          <div className="flex items-center gap-[3px]">
            <div className="w-[2.5px] h-[10px] bg-white dark:bg-black rounded-full" />
            <div className="w-[2.5px] h-[14px] bg-white dark:bg-black rounded-full" />
            <div className="w-[2.5px] h-[18px] bg-white dark:bg-black rounded-full" />
            <div className="w-[2.5px] h-[14px] bg-white dark:bg-black rounded-full" />
            <div className="w-[2.5px] h-[10px] bg-white dark:bg-black rounded-full" />
          </div>
        )}
      </button>
    </div>
  )

  return (
    <div className="flex flex-col h-screen w-full bg-background transition-colors duration-500 overflow-hidden relative">

      {/* 顶部居中导航与通知 */}
      <div className="absolute top-0 left-0 right-0 flex flex-col items-center pt-6 z-40 pointer-events-none">
        <div className="pointer-events-auto flex flex-col items-center">
          <nav className="flex justify-center gap-6 md:gap-8 text-[15px] font-medium text-muted-foreground mb-4">
            <span className="text-foreground cursor-pointer">发现</span>
            <span className="hover:text-foreground cursor-pointer transition-colors">金融</span>
            <span className="hover:text-foreground cursor-pointer transition-colors">健康</span>
            <span className="hover:text-foreground cursor-pointer transition-colors">学术</span>
            <span className="hover:text-foreground cursor-pointer transition-colors">专利</span>
          </nav>

          <div className="flex items-center bg-background/40 backdrop-blur-md border border-muted-foreground/30 hover:border-muted-foreground/50 transition-colors rounded-full pl-1.5 pr-4 py-1.5 cursor-pointer">
            <span className="bg-[#1f2f32] dark:bg-[#1a2b2e] text-[#4db8a6] px-3 py-1 rounded-full text-[11px] font-medium tracking-wide mr-3">
              New
            </span>
            <span className="text-sm text-foreground/90 mr-3">电脑现已在专业版中提供</span>
            <div className="w-[1px] h-4 bg-muted-foreground/30 mr-3"></div>
            <span className="text-muted-foreground flex items-center text-sm hover:text-foreground transition-colors">
              升级 <ArrowRight size={14} className="ml-1 opacity-80" />
            </span>
          </div>
        </div>
      </div>

      {/* 顶部主题切换按钮 */}
      <header className="absolute top-0 w-full p-4 flex justify-end items-center z-50 pointer-events-none">
        <Button
          variant="outline"
          className="rounded-full w-28 bg-background/50 backdrop-blur-md pointer-events-auto"
          onClick={() => setTheme(theme === "dark" ? "light" : "dark")}
        >
          {mounted ? (
            <>
              {theme === "dark" ? <Sun className="h-4 w-4 mr-2" /> : <Moon className="h-4 w-4 mr-2" />}
              {theme === "dark" ? "极简白" : "极夜黑"}
            </>
          ) : (
            <span className="opacity-0">载入中</span>
          )}
        </Button>
      </header>

      {view === 'course' ? (
        <>
          <ScrollArea className="flex-1 px-4 pt-32 pb-40 h-full">
            <div className="max-w-3xl mx-auto flex flex-col gap-6 animate-in fade-in duration-500">
              <div className="mb-6 pt-4">
                <h1 className="text-3xl font-bold tracking-tight">进阶课程</h1>
                <p className="text-muted-foreground mt-2">打磨 15 年的工业级经验，现已全面开放。</p>
              </div>
              {COURSE_LIST.map((course) => (
                <Card key={course.id} className="rounded-[2rem] border-muted/30 bg-secondary/30 hover:bg-secondary/60 transition-colors cursor-pointer border-t border-white/10 shadow-sm">
                  <CardHeader>
                    <div className="flex justify-between items-start">
                      <div className="text-xs font-medium text-muted-foreground mb-3 px-3 py-1 bg-background/50 rounded-full w-fit">
                        {course.tag}
                      </div>
                      <div className="text-2xl font-bold">{course.price}</div>
                    </div>
                    <CardTitle className="text-xl md:text-2xl leading-relaxed">{course.title}</CardTitle>
                    <CardDescription className="text-base mt-2">{course.desc}</CardDescription>
                  </CardHeader>
                  <CardFooter className="flex justify-end pt-2 pb-6 pr-6">
                    <Button
                      className="rounded-full px-6 bg-foreground text-background font-semibold"
                      onClick={() => router.push(`/course/${course.id}`)}
                    >
                      立即学习
                    </Button>
                  </CardFooter>
                </Card>
              ))}
            </div>
          </ScrollArea>

          <div className="absolute bottom-8 left-0 right-0 w-full max-w-3xl mx-auto px-4 z-40 animate-in slide-in-from-bottom-6 duration-500">
            {ChatInput}
          </div>
        </>
      ) : messages.length === 0 ? (
        <div className="flex-1 flex flex-col items-center justify-center px-4 pt-16">
          <div className="w-full max-w-3xl flex flex-col items-center gap-10 animate-in fade-in slide-in-from-bottom-4 duration-1000">
            <div className="text-center flex flex-col gap-4">
              <h2 className="text-xl md:text-2xl font-medium text-muted-foreground tracking-widest">
                每一天都是新的旅程，
              </h2>
              <h1 className="text-4xl md:text-5xl font-extrabold tracking-widest bg-gradient-to-r from-foreground to-muted-foreground bg-clip-text text-transparent py-2">
                勤问、多学、善用，
              </h1>
              <h2 className="text-xl md:text-2xl font-medium text-muted-foreground tracking-widest">
                你终将遇见更好的自己。
              </h2>
            </div>

            {ChatInput}

            <div className="flex flex-wrap justify-center gap-2 mt-2">
              {['✂️ 样板缩水率', '📐 领口放码', '📖 学习课程'].map(item => (
                <Button
                  key={item}
                  variant="outline"
                  className="rounded-full text-xs h-8 text-muted-foreground bg-background/50 backdrop-blur-sm"
                  onClick={() => {
                    if (item === '📖 学习课程') setView('course')
                    else setInput(item.replace(/^[^\s]+\s/, ''))
                  }}
                >
                  {item}
                </Button>
              ))}
            </div>
          </div>
        </div>
      ) : (
        <>
          <ScrollArea className="flex-1 px-4 pt-32 pb-40 h-full">
            <div className="max-w-3xl mx-auto flex flex-col gap-8">
              {messages.map((msg, i) => (
                <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                  <div className={`p-4 px-6 rounded-[2rem] max-w-[85%] leading-relaxed shadow-sm ${msg.role === 'user' ? 'bg-secondary text-secondary-foreground rounded-tr-sm' : 'bg-transparent border border-muted/50'
                    }`}>
                    {msg.content}
                  </div>
                </div>
              ))}
            </div>
          </ScrollArea>

          <div className="absolute bottom-8 left-0 right-0 w-full max-w-3xl mx-auto px-4 z-40 animate-in slide-in-from-bottom-6 duration-500">
            {ChatInput}
          </div>
        </>
      )}
    </div>
  )
}